    try:
        payload_bytes = base64url_decode(parts[1])
        result["payload"] = json.loads(payload_bytes)
    except (json.JSONDecodeError, Exception) as e:
        result["errors"].append(f"Failed to decode payload: {e}")

    # Store signature
    result["signature"] = parts[2]

    # Check expiration
    if result["payload"] and "exp" in result["payload"]:
        exp_timestamp = result["payload"]["exp"]
        current_time = time.time()
        result["is_expired"] = current_time > exp_timestamp
        if result["is_expired"]:
            expired_ago = current_time - exp_timestamp
            result["errors"].append(
                f"Token expired {expired_ago:.0f} seconds ago "
                f"(at {time.strftime('%Y-%m-%d %H:%M:%S UTC', time.gmtime(exp_timestamp))})"
            )
    else:
        result["errors"].append("No 'exp' claim found in payload — token has no expiration")

    # Check 'not before' claim
    if result["payload"] and "nbf" in result["payload"]:
        nbf_timestamp = result["payload"]["nbf"]
        current_time = time.time()
        if current_time < nbf_timestamp:
            result["errors"].append(
                f"Token is not yet valid (nbf: "
                f"{time.strftime('%Y-%m-%d %H:%M:%S UTC', time.gmtime(nbf_timestamp))})"
            )

    # Verify signature if requested
    if verify:
        if secret is None:
            result["errors"].append("Cannot verify signature: no secret provided")
            result["signature_valid"] = False
        elif result["header"] is None:
            result["errors"].append("Cannot verify signature: header could not be decoded")
            result["signature_valid"] = False
        else:
            alg = result["header"].get("alg", "").upper()
            signing_input = f"{parts[0]}.{parts[1]}".encode("utf-8")
            secret_bytes = secret.encode("utf-8") if isinstance(secret, str) else secret

            hash_algorithms = {
                "HS256": hashlib.sha256,
                "HS384": hashlib.sha384,
                "HS512": hashlib.sha512,
            }

