    print("JWT TOKEN INSPECTION")
    print("=" * 60)

    print("\n--- HEADER ---")
    if result["header"]:
        print(json.dumps(result["header"], indent=2))
    else:
        print("  (could not decode)")

    print("\n--- PAYLOAD (CLAIMS) ---")
    if result["payload"]:
        print(json.dumps(result["payload"], indent=2))
        # Annotate time-based claims
        for claim_name, label in [("exp", "Expires"), ("iat", "Issued At"), ("nbf", "Not Before")]:
            if claim_name in result["payload"]:
                ts = result["payload"][claim_name]
                human_time = time.strftime("%Y-%m-%d %H:%M:%S UTC", time.gmtime(ts))
                print(f"  >> {label}: {human_time}")
    else:
        print("  (could not decode)")

    print("\n--- SIGNATURE ---")
    print(f"  Raw (base64url): {result['signature']}")
    if result["signature_valid"] is True:
        print("  ✅ Signature is VALID")
    elif result["signature_valid"] is False:
        print("  ❌ Signature is INVALID")
    else:
        print("  ⚠️  Signature not verified (pass verify=True and secret to verify)")

    print("\n--- EXPIRATION ---")
    if result["is_expired"] is True:
        print("  ❌ Token is EXPIRED")
    elif result["is_expired"] is False:
        print("  ✅ Token is NOT expired")
    else:
        print("  ⚠️  No expiration claim found")

    if result["errors"]:
        print("\n--- ISSUES FOUND ---")
        for i, error in enumerate(result["errors"], 1):
            print(f"  {i}. {error}")

    print("\n" + "=" * 60)


